import * as React from 'react';
import { graphql, Link } from 'gatsby';
import { Layout } from '~src/context/Layout';
import { Breadcrumb } from '~src/components/Breadcrumb';
import { GatsbyImage as Img } from 'gatsby-plugin-image';
import { formatDate } from '~src/_utils/fortmatDate';

const PostTemplate = ({ data }) => {
  const seo = {
    title: data.wpPost.title,
    article: true,
    image: data.wpPost.featuredImage.node.localFile.childImageSharp.gatsbyImageData.images.fallback.src,
  };
  return (
    <Layout seo={seo}>
      <section className="uk-section-muted uk-section-small">
        <div className="uk-container">
          <div className="uk-grid-medium uk-child-width-1-1" data-uk-grid>
            <Breadcrumb currentPage={data.wpPost.title} />
            <section>
              <div>
                <article className="uk-card uk-card-default uk-card-body uk-artictle">
                  <header className="uk-text-center">
                    <h1 className="uk-article-title">{data.wpPost.title}</h1>
                  </header>
                  <div className="tm-wrapper uk-text-center">
                    <figure>
                      <span>
                        <Img
                          image={data.wpPost.featuredImage.node.localFile.childImageSharp.gatsbyImageData}
                          alt={data.wpPost.featuredImage.node.title}
                          data-uk-cover
                        />
                      </span>
                      <figcaption>{data.wpPost.title}</figcaption>
                    </figure>
                  </div>
                  <div className="uk-article-body">
                    <div dangerouslySetInnerHTML={{ __html: data.wpPost.content }}></div>
                  </div>
                </article>
              </div>
            </section>
            <section>
              <h2 className="uk-text-center">مطالب مرتبط</h2>
              <div
                className="uk-grid-medium uk-grid-match uk-child-width-1-1 uk-child-width-1-2@s uk-child-width-1-4@m"
                data-uk-grid>
                {/* need map here */}
                {data.wpPost.tags?.nodes[0].posts.nodes.map(post => (
                  <div key={post.id}>
                    <Link to={post.uri}>
                      <article className="uk-card uk-card-default uk-card-small uk-overflow-hidden uk-link-heading uk-display-block uk-box-shadow-hover-large uk-height-1-1 tm-ignore-container">
                        <div className="uk-card-media-top">
                          <figure className="uk-margin-remove tm-ratio tm-ratio-16-9">
                            <div className="uk-cover-container">
                              <Img
                                image={post.featuredImage.node.localFile.childImageSharp.gatsbyImageData}
                                alt={post.featuredImage.node.title}
                                data-uk-cover
                              />
                              {/*   <img src="article.preview" alt="article.title" data-uk-cover /> */}
                            </div>
                          </figure>
                        </div>
                        <div className="uk-card-body">
                          <div className="uk-article-meta uk-margin-xsmall-bottom">
                            <time>{formatDate(post.date)}</time>
                          </div>
                          <h3 className="uk-h4 uk-margin-remove">{post.title}</h3>
                        </div>
                      </article>
                    </Link>
                  </div>
                ))}
              </div>
            </section>
          </div>
        </div>
      </section>
    </Layout>
  );
};

export default PostTemplate;
export const query = graphql`
  query PostTemplateQuery($id: String) {
    wpPost(id: { eq: $id }) {
      id
      title
      content
      featuredImage {
        node {
          title
          localFile {
            childImageSharp {
              gatsbyImageData(layout: FULL_WIDTH)
            }
          }
        }
      }
      tags {
        nodes {
          posts {
            nodes {
              id
              title
              date
              uri
              featuredImage {
                node {
                  title
                  localFile {
                    childImageSharp {
                      gatsbyImageData(layout: FULL_WIDTH)
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
`;
